//! Death #2 — Scattering-amplitude attention (forward-pass wiring layer).
//!
//! This module is the attention-mechanism wrapper that *consumes*
//! [`crate::scattering_amplitude`] (the Lean-formalised
//! Plücker / KPlane / amplitude kernel) and turns it into a drop-in
//! alternative to softmax(Q K^T / sqrt(d_head)) @ V over a single head.
//!
//! Module split rationale (mirrors `amplituhedron.rs` ↔
//! `scattering_amplitude.rs`):
//!
//!   * `scattering_amplitude.rs` — pure Lean-mirrored math (i64). No
//!     attention concept, no Q/K/V, no quantization. Touching it requires
//!     re-proving the Lean oracles.
//!   * `scattering_attention.rs` (this file) — the attention application.
//!     Owns the f32→i64 quantization, the standing-wave-subspace
//!     projection, the per-(i,j) KPlane construction, the softmax over
//!     amplitudes, and the value mixing. Touching it does *not* touch
//!     the Lean contract.
//!
//! ## Status
//!
//! **Additive only.** Nothing in `model.rs::forward_range_chunk` calls
//! these functions. They live alongside the existing softmax path so
//! Taylor can A/B the parity numbers (see
//! `tests::amplituhedron_attention_vs_softmax_divergence`) before
//! deciding whether to flip the default.
//!
//! ## Math sketch
//!
//! For each query position `i ∈ [0, seq_len)`:
//!   1. Project `q_i` onto the standing-wave subspace: `q_i^k = q_i[swd]`
//!      (where `swd = standing_wave_dims`, |swd| = k_sub).
//!   2. For each key position `j ∈ [0, seq_len)`:
//!      a. Project `k_j` similarly: `k_j^k`.
//!      b. Build a 2-plane in `k_sub`-space from `[q_i^k; k_j^k]` —
//!         a `KPlane { k=2, d=k_sub }`.
//!      c. Compute Plücker coordinates and contract against the all-ones
//!         dual covector to obtain the scattering amplitude
//!         `A(i,j) = scattering_amplitude(plane, [1,1,...,1])`.
//!   3. Softmax `A(i, ·)` over `j` to obtain attention weights.
//!   4. Output `out_i = Σ_j w(i,j) · v_j`.
//!
//! The dual = all-ones covector matches the Lean oracle
//! `vandermonde_2_4_amplitude` (which contracts `[36,30,19,6,5,1]` with
//! `[1,1,1,1,1,1]` to get `97`). It is a deliberate choice — other duals
//! give different attention mechanisms; this one is the canonical
//! "uniform-weighted Plücker sum" baseline.
//!
//! ## Quantization
//!
//! `KPlane` stores `i64`. Real Q, K, V tensors are `f32`. We map
//! `f32 → i64` via `round(x * SCALE)` with `SCALE = 1024.0` (10 bits of
//! fraction). This bounds rounding error to `±0.5 / SCALE ≈ ±5e-4` per
//! coordinate. After computing the i64 amplitude, we divide by
//! `SCALE^k` (here `k = 2`, since the plane has 2 rows so each Plücker
//! minor is a 2×2 determinant scaling as `SCALE^2`) before softmax. We
//! also rescale by `1 / sqrt(k_sub)` to keep the pre-softmax magnitude
//! comparable to standard scaled-dot-product attention.
//!
//! Overflow envelope: a 2×2 minor is `q_a * k_b - q_b * k_a`. With
//! `|q|,|k| ≤ ~3` (typical post-RMSNorm magnitude) and `SCALE = 1024`,
//! each i64 entry is at most ~3072, each minor at most ~2 * 3072² ≈ 1.9e7.
//! Summed over `C(k_sub, 2)` minors at, say, `k_sub = 32` → 496 minors,
//! the total stays under 1e10 — comfortably inside i64 (≤ ~9.2e18).
//! If a future caller pushes `k_sub > 256` or feeds in unnormalized
//! activations, this bound must be revisited.
//!
//! ## What this is NOT
//!
//! This is not a multi-head wrapper. The caller is expected to slice
//! Q/K/V per-head and call this once per head. There is no positional
//! embedding, no causal mask, no KV-cache integration — the goal is the
//! cleanest possible parity surface against textbook softmax attention.

#![allow(dead_code)]

use crate::scattering_amplitude::{scattering_amplitude, KPlane};

// ════════════════════════════════════════════════════════════════════
// QUANTIZATION CONSTANTS
// ════════════════════════════════════════════════════════════════════

/// f32 → i64 fixed-point scale. 10 bits of fraction. See module docs
/// for the overflow envelope analysis.
const QUANT_SCALE: f32 = 1024.0;

/// `SCALE^2` — the divisor for 2×2-minor amplitudes when reading the
/// i64 result back as f32. Each Plücker coordinate of a 2-plane is a
/// determinant of a 2×2 submatrix, so it scales as `SCALE^2`.
const QUANT_SCALE_SQ: f32 = QUANT_SCALE * QUANT_SCALE;

/// Quantize an f32 row to i64 by `round(x * SCALE)`.
#[inline]
fn quantize_row(row: &[f32]) -> Vec<i64> {
    row.iter()
        .map(|&v| (v * QUANT_SCALE).round() as i64)
        .collect()
}

// ════════════════════════════════════════════════════════════════════
// SOFTMAX HELPER (numerically stable, in-place over a row)
// ════════════════════════════════════════════════════════════════════

/// Numerically stable softmax over a slice. Subtracts the max before
/// exponentiating to avoid overflow on large logits.
fn softmax_inplace(row: &mut [f32]) {
    if row.is_empty() {
        return;
    }
    let max = row.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let mut sum = 0.0_f32;
    for v in row.iter_mut() {
        *v = (*v - max).exp();
        sum += *v;
    }
    if sum > 0.0 {
        let inv = 1.0 / sum;
        for v in row.iter_mut() {
            *v *= inv;
        }
    }
}

// ════════════════════════════════════════════════════════════════════
// REFERENCE: TEXTBOOK SOFTMAX ATTENTION
// ════════════════════════════════════════════════════════════════════

/// Single-head scaled dot-product attention:
///   out = softmax(Q K^T / sqrt(d_head)) @ V
///
/// Inputs are row-major:
///   q: [seq_len, d_head]
///   k: [seq_len, d_head]
///   v: [seq_len, d_head]
///
/// Output: [seq_len, d_head]
///
/// This exists as the controlled reference for the parity test against
/// [`attention_via_amplituhedron`]. No causal mask, no positional bias,
/// no multi-head — single-head only.
pub fn attention_via_softmax(
    q: &[f32],
    k: &[f32],
    v: &[f32],
    seq_len: usize,
    d_head: usize,
) -> Vec<f32> {
    assert_eq!(q.len(), seq_len * d_head, "q shape mismatch");
    assert_eq!(k.len(), seq_len * d_head, "k shape mismatch");
    assert_eq!(v.len(), seq_len * d_head, "v shape mismatch");

    let scale = 1.0 / (d_head as f32).sqrt();
    let mut out = vec![0.0_f32; seq_len * d_head];
    let mut logits = vec![0.0_f32; seq_len];

    for i in 0..seq_len {
        let q_row = &q[i * d_head..(i + 1) * d_head];
        for j in 0..seq_len {
            let k_row = &k[j * d_head..(j + 1) * d_head];
            let mut dot = 0.0_f32;
            for d in 0..d_head {
                dot += q_row[d] * k_row[d];
            }
            logits[j] = dot * scale;
        }
        softmax_inplace(&mut logits);
        for j in 0..seq_len {
            let w = logits[j];
            let v_row = &v[j * d_head..(j + 1) * d_head];
            let out_row = &mut out[i * d_head..(i + 1) * d_head];
            for d in 0..d_head {
                out_row[d] += w * v_row[d];
            }
        }
    }
    out
}

// ════════════════════════════════════════════════════════════════════
// AMPLITUHEDRON ATTENTION
// ════════════════════════════════════════════════════════════════════

/// Single-head attention via amplituhedron scattering amplitudes.
///
/// Drop-in alternative to [`attention_via_softmax`]. See module docs
/// for the math sketch and quantization analysis.
///
/// `standing_wave_dims` is the index set of "standing-wave" dimensions
/// extracted upstream (typically post-RMSNorm) — a subset of
/// `[0..d_head)`. The amplitude computation runs on the projection of
/// Q and K onto these dimensions; the value mixing in step 4 still
/// uses the full d_head V vector.
///
/// Edge cases:
///   * `standing_wave_dims.len() < 2`: the 2-plane is degenerate
///     (rank < 2). Returns the all-ones-attention output (uniform mix
///     of V over keys) — same effective behavior as a softmax with
///     zero logits — and a warning would be logged in production
///     (the test path verifies finiteness, not silent drop).
///   * `seq_len == 0`: returns an empty Vec.
///
/// The dual covector for the amplitude inner product is the all-ones
/// vector of length `C(k_sub, 2)`, matching the Lean oracle
/// `vandermonde_2_4_amplitude`.
pub fn attention_via_amplituhedron(
    q: &[f32],
    k: &[f32],
    v: &[f32],
    seq_len: usize,
    d_head: usize,
    standing_wave_dims: &[usize],
) -> Vec<f32> {
    assert_eq!(q.len(), seq_len * d_head, "q shape mismatch");
    assert_eq!(k.len(), seq_len * d_head, "k shape mismatch");
    assert_eq!(v.len(), seq_len * d_head, "v shape mismatch");

    if seq_len == 0 {
        return Vec::new();
    }

    let k_sub = standing_wave_dims.len();
    let mut out = vec![0.0_f32; seq_len * d_head];

    // Degenerate subspace: a 2-plane needs ≥ 2 columns. Fall back to a
    // uniform-weighted V mix (equivalent to softmax over zero logits).
    if k_sub < 2 {
        let w = 1.0 / (seq_len as f32);
        for i in 0..seq_len {
            for j in 0..seq_len {
                let v_row = &v[j * d_head..(j + 1) * d_head];
                let out_row = &mut out[i * d_head..(i + 1) * d_head];
                for d in 0..d_head {
                    out_row[d] += w * v_row[d];
                }
            }
        }
        return out;
    }

    // Validate standing_wave_dims are in range; clamp silently rather
    // than panic so a stale upstream config (e.g. dims for a different
    // head dim) at least produces finite output the parity test can
    // surface.
    let swd: Vec<usize> = standing_wave_dims
        .iter()
        .copied()
        .filter(|&d| d < d_head)
        .collect();
    if swd.len() < 2 {
        let w = 1.0 / (seq_len as f32);
        for i in 0..seq_len {
            for j in 0..seq_len {
                let v_row = &v[j * d_head..(j + 1) * d_head];
                let out_row = &mut out[i * d_head..(i + 1) * d_head];
                for d in 0..d_head {
                    out_row[d] += w * v_row[d];
                }
            }
        }
        return out;
    }
    let k_sub = swd.len();

    // Pre-quantize Q and K projected onto the standing-wave subspace.
    // Per-row Vec<i64> of length k_sub.
    let mut q_proj_q: Vec<Vec<i64>> = Vec::with_capacity(seq_len);
    let mut k_proj_q: Vec<Vec<i64>> = Vec::with_capacity(seq_len);
    for i in 0..seq_len {
        let q_row = &q[i * d_head..(i + 1) * d_head];
        let k_row = &k[i * d_head..(i + 1) * d_head];
        let q_sub: Vec<f32> = swd.iter().map(|&d| q_row[d]).collect();
        let k_sub_row: Vec<f32> = swd.iter().map(|&d| k_row[d]).collect();
        q_proj_q.push(quantize_row(&q_sub));
        k_proj_q.push(quantize_row(&k_sub_row));
    }

    // Number of Plücker coords for KPlane(k=2, d=k_sub) is C(k_sub, 2).
    // Build the all-ones dual covector once.
    let n_minors = k_sub * (k_sub - 1) / 2;
    let dual: Vec<i64> = vec![1_i64; n_minors];

    // Read-back rescale: each minor is a 2×2 determinant in i64
    // fixed-point, which scales as SCALE^2. We divide first, then apply
    // the standard 1/sqrt(d_head_subspace) attention scale to keep the
    // pre-softmax magnitude in the same ballpark as softmax attention.
    let amp_rescale = (1.0 / QUANT_SCALE_SQ) * (1.0 / (k_sub as f32).sqrt());

    let mut logits = vec![0.0_f32; seq_len];

    for i in 0..seq_len {
        let q_i = &q_proj_q[i];
        for j in 0..seq_len {
            let k_j = &k_proj_q[j];
            // KPlane k=2, d=k_sub. Construction errors here would mean a
            // bug in our shape bookkeeping above; surface as a panic
            // because that is a programming error, not a runtime input
            // problem.
            let plane = KPlane::new(2, k_sub, vec![q_i.clone(), k_j.clone()])
                .expect("scattering_attention: KPlane shape invariant violated");
            let amp_i64 = scattering_amplitude(&plane, &dual);
            // Cast through f64 to preserve precision before the divide.
            logits[j] = (amp_i64 as f64) as f32 * amp_rescale;
        }
        softmax_inplace(&mut logits);
        for j in 0..seq_len {
            let w = logits[j];
            let v_row = &v[j * d_head..(j + 1) * d_head];
            let out_row = &mut out[i * d_head..(i + 1) * d_head];
            for d in 0..d_head {
                out_row[d] += w * v_row[d];
            }
        }
    }
    out
}

// ════════════════════════════════════════════════════════════════════
// PARITY TESTS
// ════════════════════════════════════════════════════════════════════

#[cfg(test)]
mod tests {
    use super::*;

    /// Deterministic pseudo-random f32 in roughly [-1, 1] from a seed and
    /// index. Avoids pulling in a dev-deps RNG and keeps the test
    /// reproducible across machines.
    fn synth(seed: u64, idx: usize) -> f32 {
        // SplitMix64-style scramble, then map to [-1, 1].
        let mut z = seed.wrapping_add((idx as u64).wrapping_mul(0x9E37_79B9_7F4A_7C15));
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^= z >> 31;
        // Take top 24 bits as a uniform [0, 1) and stretch to [-1, 1].
        let u = ((z >> 40) as f32) / ((1u32 << 24) as f32);
        2.0 * u - 1.0
    }

    fn cosine(a: &[f32], b: &[f32]) -> f32 {
        let mut dot = 0.0_f64;
        let mut na = 0.0_f64;
        let mut nb = 0.0_f64;
        for (&x, &y) in a.iter().zip(b.iter()) {
            dot += (x as f64) * (y as f64);
            na += (x as f64) * (x as f64);
            nb += (y as f64) * (y as f64);
        }
        let denom = (na.sqrt() * nb.sqrt()).max(1e-12);
        (dot / denom) as f32
    }

    #[test]
    fn softmax_attention_uniform_q_k_yields_uniform_weights() {
        // If Q and K are all zeros, attention weights are uniform 1/seq_len
        // and output equals the average of V rows.
        let seq_len = 3;
        let d_head = 4;
        let q = vec![0.0_f32; seq_len * d_head];
        let k = vec![0.0_f32; seq_len * d_head];
        let mut v = vec![0.0_f32; seq_len * d_head];
        for j in 0..seq_len {
            for d in 0..d_head {
                v[j * d_head + d] = (j * d_head + d) as f32;
            }
        }
        let out = attention_via_softmax(&q, &k, &v, seq_len, d_head);
        // Average of v rows: row_avg[d] = (v[0,d] + v[1,d] + v[2,d]) / 3
        for d in 0..d_head {
            let avg = (v[d] + v[d_head + d] + v[2 * d_head + d]) / 3.0;
            for i in 0..seq_len {
                let got = out[i * d_head + d];
                assert!(
                    (got - avg).abs() < 1e-5,
                    "softmax uniform mismatch at i={i} d={d}: got {got} expected {avg}"
                );
            }
        }
    }

    #[test]
    fn amplituhedron_attention_finite_on_synthetic_input() {
        // Tiny synthetic Q/K/V — verify outputs are finite (no NaN/Inf).
        let seq_len = 4;
        let d_head = 8;
        let q: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xA1, i)).collect();
        let k: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xA2, i)).collect();
        let v: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xA3, i)).collect();
        let swd = vec![0_usize, 2, 5];
        let out = attention_via_amplituhedron(&q, &k, &v, seq_len, d_head, &swd);
        assert_eq!(out.len(), seq_len * d_head);
        for (idx, x) in out.iter().enumerate() {
            assert!(x.is_finite(), "non-finite output at index {idx}: {x}");
        }
    }

    #[test]
    fn amplituhedron_attention_handles_degenerate_subspace() {
        // standing_wave_dims with < 2 dims: must fall back to uniform mix,
        // not panic, not produce NaN.
        let seq_len = 3;
        let d_head = 4;
        let q: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xB1, i)).collect();
        let k: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xB2, i)).collect();
        let v: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xB3, i)).collect();
        let swd_zero: Vec<usize> = vec![];
        let out_zero = attention_via_amplituhedron(&q, &k, &v, seq_len, d_head, &swd_zero);
        assert_eq!(out_zero.len(), seq_len * d_head);
        for x in &out_zero {
            assert!(x.is_finite(), "degenerate (k_sub=0) produced non-finite");
        }
        let swd_one = vec![3_usize];
        let out_one = attention_via_amplituhedron(&q, &k, &v, seq_len, d_head, &swd_one);
        for x in &out_one {
            assert!(x.is_finite(), "degenerate (k_sub=1) produced non-finite");
        }
    }

    /// THE PARITY TEST — DOES NOT ASSERT NUMERICAL EQUALITY.
    ///
    /// Surfaces the divergence numbers between amplituhedron attention
    /// and softmax attention so Taylor can decide whether to flip the
    /// default. Use `cargo test --lib amplituhedron_attention_vs_softmax_divergence -- --nocapture`
    /// to see the eprintln! output.
    #[test]
    fn amplituhedron_attention_vs_softmax_divergence() {
        let seq_len = 4;
        let d_head = 8;
        let q: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xC0DE, i)).collect();
        let k: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xC0DF, i)).collect();
        let v: Vec<f32> = (0..seq_len * d_head).map(|i| synth(0xC0E0, i)).collect();
        // 3 of 8 dims = 37.5% coverage, matches the integration plan target.
        let swd = vec![0_usize, 2, 5];

        let out_sm = attention_via_softmax(&q, &k, &v, seq_len, d_head);
        let out_am = attention_via_amplituhedron(&q, &k, &v, seq_len, d_head, &swd);

        // Shape and finiteness checks (these ARE asserted — divergence
        // analysis is meaningless if either output is corrupted).
        assert_eq!(out_sm.len(), seq_len * d_head, "softmax output shape");
        assert_eq!(out_am.len(), seq_len * d_head, "amplituhedron output shape");
        for (idx, x) in out_sm.iter().enumerate() {
            assert!(x.is_finite(), "softmax non-finite at {idx}: {x}");
        }
        for (idx, x) in out_am.iter().enumerate() {
            assert!(x.is_finite(), "amplituhedron non-finite at {idx}: {x}");
        }

        // Per-row divergence numbers.
        eprintln!();
        eprintln!("=== amplituhedron-attention vs softmax-attention divergence ===");
        eprintln!(
            "config: seq_len={} d_head={} k_sub={} (coverage={:.1}%) quant_scale={}",
            seq_len,
            d_head,
            swd.len(),
            100.0 * (swd.len() as f32) / (d_head as f32),
            QUANT_SCALE
        );
        eprintln!(
            "{:<5} {:>14} {:>14} {:>14}",
            "row", "max-abs-diff", "mean-abs-diff", "cosine-sim"
        );
        let mut total_max_diff = 0.0_f32;
        let mut total_mean_cos = 0.0_f32;
        for i in 0..seq_len {
            let sm_row = &out_sm[i * d_head..(i + 1) * d_head];
            let am_row = &out_am[i * d_head..(i + 1) * d_head];
            let mut max_diff = 0.0_f32;
            let mut sum_diff = 0.0_f32;
            for d in 0..d_head {
                let diff = (sm_row[d] - am_row[d]).abs();
                if diff > max_diff {
                    max_diff = diff;
                }
                sum_diff += diff;
            }
            let mean_diff = sum_diff / (d_head as f32);
            let cos = cosine(sm_row, am_row);
            eprintln!(
                "{:<5} {:>14.6} {:>14.6} {:>14.6}",
                i, max_diff, mean_diff, cos
            );
            total_max_diff = total_max_diff.max(max_diff);
            total_mean_cos += cos;
        }
        let mean_cos = total_mean_cos / (seq_len as f32);
        eprintln!(
            "summary: global max-abs-diff={:.6} mean cosine-sim={:.6}",
            total_max_diff, mean_cos
        );

        // Rank-preservation check: do the two attention mechanisms agree on
        // which key position each query attends to MOST? (argmax of the
        // attention weight row.) This is a coarser but more
        // semantically meaningful parity signal than per-element diff.
        eprintln!();
        eprintln!("=== argmax(attention_weights) per query (rank-preservation) ===");
        let scale = 1.0 / (d_head as f32).sqrt();
        let k_sub = swd.len();
        let n_minors = k_sub * (k_sub - 1) / 2;
        let dual: Vec<i64> = vec![1_i64; n_minors];
        let amp_rescale = (1.0 / QUANT_SCALE_SQ) * (1.0 / (k_sub as f32).sqrt());

        let mut argmax_match = 0_usize;
        for i in 0..seq_len {
            let q_row = &q[i * d_head..(i + 1) * d_head];
            // Softmax logits.
            let mut sm_logits = vec![0.0_f32; seq_len];
            for j in 0..seq_len {
                let k_row = &k[j * d_head..(j + 1) * d_head];
                let mut dot = 0.0_f32;
                for d in 0..d_head {
                    dot += q_row[d] * k_row[d];
                }
                sm_logits[j] = dot * scale;
            }
            // Amplituhedron logits.
            let q_sub: Vec<f32> = swd.iter().map(|&d| q_row[d]).collect();
            let q_q = quantize_row(&q_sub);
            let mut am_logits = vec![0.0_f32; seq_len];
            for j in 0..seq_len {
                let k_row = &k[j * d_head..(j + 1) * d_head];
                let k_sub_row: Vec<f32> = swd.iter().map(|&d| k_row[d]).collect();
                let k_q = quantize_row(&k_sub_row);
                let plane = KPlane::new(2, k_sub, vec![q_q.clone(), k_q]).unwrap();
                am_logits[j] = (scattering_amplitude(&plane, &dual) as f64) as f32 * amp_rescale;
            }
            let sm_argmax = sm_logits
                .iter()
                .enumerate()
                .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
                .map(|(i, _)| i)
                .unwrap();
            let am_argmax = am_logits
                .iter()
                .enumerate()
                .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
                .map(|(i, _)| i)
                .unwrap();
            let agree = sm_argmax == am_argmax;
            if agree {
                argmax_match += 1;
            }
            eprintln!(
                "query {:<2} softmax argmax={} amplituhedron argmax={} agree={}",
                i, sm_argmax, am_argmax, agree
            );
        }
        eprintln!(
            "argmax agreement: {}/{} ({:.1}%)",
            argmax_match,
            seq_len,
            100.0 * (argmax_match as f32) / (seq_len as f32)
        );
        eprintln!();

        // Deliberately no equality assertion. Test PROVES they diverge so
        // we can decide. Keep the test green so CI stays green; the
        // numbers above are for human inspection.
    }
}
